<span class="line">	<span class="token boolean">_</span><span class="token punctuation">,</span> err <span class="token operator">:=</span> r<span class="token punctuation">.</span>client<span class="token punctuation">.</span><span class="token function">InsertMany</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> CollectionCandle<span class="token punctuation">,</span> <span class="token string">&quot;&quot;</span><span class="token punctuation">,</span> docs<span class="token punctuation">)</span></span>
