<span class="line">		<span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> candleV1<span class="token punctuation">.</span><span class="token function">ErrorInternalServerError</span><span class="token punctuation">(</span><span class="token string">&quot;query candle count failed&quot;</span><span class="token punctuation">)</span></span>
